module up_down_counter(
    input rst,
    input reset,
    input up,
    input down,
    output reg [3:0] count
);

    always @(posedge rst) begin
        if (reset)
            count <= 0;
        else if (up & ~down)
            count <= count + 1;
        else if (~up & down)
            count <= count - 1;
    end

endmodule
